insert into places (id, city_id, added_by, name, category, priority, lat, lng, address, payment, hours_note, reservation_required, notes, summary) values
  ('d0000000-0000-0000-0000-000000000001', 'c0000000-0000-0000-0000-000000000001', 'b0000000-0000-0000-0000-000000000001', '再回首凉鸡米线', 'noodles', 'must_go', 25.6901, 100.1645, '大理古城人民路 1号', '{wechat_pay,alipay,cash}', '早上7点到下午3点，卖完即止', false, '大理最有名的米线店，凉鸡米线是招牌。早点去排队少。', '必吃！凉鸡米线+卤鸡皮，早上去避开人流。'),
  ('d0000000-0000-0000-0000-000000000002', 'c0000000-0000-0000-0000-000000000001', 'b0000000-0000-0000-0000-000000000001', '杨记烤乳扇', 'street_food', 'must_go', 25.6905, 100.1640, '大理古城复兴路', '{wechat_pay,alipay,cash}', '全天营业', false, '烤乳扇是大理特色，玫瑰酱口味最经典。', '烤乳扇选玫瑰酱味，10块一个。'),
  ('d0000000-0000-0000-0000-000000000003', 'c0000000-0000-0000-0000-000000000001', 'b0000000-0000-0000-0000-000000000001', '石井私房菜', 'dinner', 'must_go', 25.6890, 100.1650, '大理古城博爱路 99号', '{wechat_pay,alipay}', '11:00-14:00, 17:00-21:00', true, '本地人推荐的私房菜，酸辣鱼必点。提前一天预约。', '酸辣鱼 + 老奶洋芋 + 水性杨花，提前预约。'),
  ('d0000000-0000-0000-0000-000000000004', 'c0000000-0000-0000-0000-000000000001', 'b0000000-0000-0000-0000-000000000001', '海稍鱼·翠田餐厅', 'lunch', 'want_to', 25.5900, 100.2200, '大理市下关镇洱海边', '{wechat_pay,alipay}', '11:00-21:00', false, '洱海边吃鱼，环境好。海稍鱼是洱海特色做法。', '洱海边景观位吃海稍鱼，人均80。'),
  ('d0000000-0000-0000-0000-000000000005', 'c0000000-0000-0000-0000-000000000001', 'b0000000-0000-0000-0000-000000000001', '喜洲粑粑·和尚老铺', 'breakfast', 'must_go', 25.7330, 100.1480, '喜洲古镇四方街', '{wechat_pay,cash}', '早上8点开始，下午卖完收摊', false, '喜洲粑粑是大理传统小吃，甜咸两种口味，咸味更好。', '咸味粑粑 > 甜味，刚出炉的最好吃。'),
  ('d0000000-0000-0000-0000-000000000006', 'c0000000-0000-0000-0000-000000000001', 'b0000000-0000-0000-0000-000000000001', 'Bad Monkey 咖啡', 'cafe', 'want_to', 25.6895, 100.1643, '大理古城人民路上段', '{wechat_pay,alipay}', '9:00-22:00', false, '人民路上很有氛围的咖啡店，可以坐很久。', null),
  ('d0000000-0000-0000-0000-000000000007', 'c0000000-0000-0000-0000-000000000001', 'b0000000-0000-0000-0000-000000000001', '巍山耙肉饵丝', 'breakfast', 'want_to', 25.6903, 100.1638, '大理古城玉洱路', '{wechat_pay,alipay,cash}', '早上6:30-下午2:00', false, '耙肉饵丝是巍山特色，肉炖得很烂，汤头鲜。', '加个卤蛋，汤要多要。'),
  ('d0000000-0000-0000-0000-000000000008', 'c0000000-0000-0000-0000-000000000001', 'b0000000-0000-0000-0000-000000000001', '大理老木瓜鸡', 'dinner', 'want_to', 25.6888, 100.1655, '大理古城洋人街附近', '{wechat_pay,alipay}', '11:00-21:30', false, '木瓜鸡是白族特色菜，酸酸甜甜很开胃。', null),
  ('d0000000-0000-0000-0000-000000000009', 'c0000000-0000-0000-0000-000000000001', 'b0000000-0000-0000-0000-000000000001', 'Serendipity 甜品店', 'dessert', 'if_time', 25.6898, 100.1646, '大理古城人民路中段', '{wechat_pay,alipay}', '10:00-21:00', false, '很多博主推荐的甜品店，芒果糯米饭好看好吃。', null),
  ('d0000000-0000-0000-0000-000000000010', 'c0000000-0000-0000-0000-000000000001', 'b0000000-0000-0000-0000-000000000001', '白族三道茶·严家大院', 'tea_house', 'want_to', 25.7340, 100.1475, '喜洲严家大院', '{wechat_pay,alipay,cash}', '9:00-17:00', false, '白族三道茶：一苦二甜三回味。喜洲严家大院的体验最正宗。', '在严家大院体验三道茶+白族歌舞，门票含茶。');
insert into sources (id, place_id, added_by, platform, url, author, caption, key_takeaway, rating_vibe) values
  ('e0000000-0000-0000-0000-000000000001', 'd0000000-0000-0000-0000-000000000001', 'b0000000-0000-0000-0000-000000000001', 'rednote', 'https://www.xiaohongshu.com/explore/dali-mixi-001', '@云南吃货日记', '大理古城必吃！这家凉鸡米线排队1小时也值得', '凉鸡米线+卤鸡皮，早上10点前去不用排队', 'loved'),
  ('e0000000-0000-0000-0000-000000000002', 'd0000000-0000-0000-0000-000000000001', 'b0000000-0000-0000-0000-000000000001', 'tiktok', 'https://www.tiktok.com/@dali_foodie/video/123456', '@dali_foodie', 'The most famous noodle shop in Dali Old Town', '点小份就够了，加辣更好吃', 'recommended'),
  ('e0000000-0000-0000-0000-000000000003', 'd0000000-0000-0000-0000-000000000001', 'b0000000-0000-0000-0000-000000000001', 'rednote', 'https://www.xiaohongshu.com/explore/dali-mixi-002', '@旅行的小鱼', '再回首的秘密菜单！除了米线还有这些', '隐藏菜单：鸡皮凉片，不在墙上菜单里要自己问', 'loved'),
  ('e0000000-0000-0000-0000-000000000004', 'd0000000-0000-0000-0000-000000000003', 'b0000000-0000-0000-0000-000000000001', 'rednote', 'https://www.xiaohongshu.com/explore/dali-shijing-001', '@大理本地通', '大理本地人才知道的私房菜馆', '酸辣鱼用的是洱海鱼，老奶洋芋也是招牌', 'loved'),
  ('e0000000-0000-0000-0000-000000000005', 'd0000000-0000-0000-0000-000000000005', 'b0000000-0000-0000-0000-000000000001', 'rednote', 'https://www.xiaohongshu.com/explore/dali-baba-001', '@喜洲古镇攻略', '喜洲粑粑哪家最正宗？本地人都来这家', '认准和尚老铺，咸味的比甜味好吃', 'loved'),
  ('e0000000-0000-0000-0000-000000000006', 'd0000000-0000-0000-0000-000000000002', 'b0000000-0000-0000-0000-000000000001', 'instagram', 'https://www.instagram.com/p/dali-rushan-001', '@yunnan.eats', 'Grilled milk fan cake with rose jam', '玫瑰酱味最经典，拍照也好看', 'recommended'),
  ('e0000000-0000-0000-0000-000000000007', 'd0000000-0000-0000-0000-000000000009', 'b0000000-0000-0000-0000-000000000001', 'rednote', 'https://www.xiaohongshu.com/explore/dali-dessert-001', '@甜品探店', '大理古城最出片的甜品店', '芒果糯米饭颜值高，味道一般般，主要是拍照', 'mixed'),
  ('e0000000-0000-0000-0000-000000000008', 'd0000000-0000-0000-0000-000000000004', 'b0000000-0000-0000-0000-000000000001', 'tiktok', 'https://www.tiktok.com/@yunnan_travel/video/789012', '@yunnan_travel', '洱海边最好吃的鱼！海稍鱼到底有多鲜', '选靠窗位看洱海，鱼是当天捞的', 'loved');
